31	/// Canonical-prefix base shape: lowercase letters, distinct cloud/runtime
32	/// pair, no trailing hyphen (the composer adds it). Cases 2-4 rely on the
33	/// composed form for state detection in rbrr.env.
34	#[test]
35	fn rbtdtk_canonical_base_shape() {
36	    assert_ne!(RBTDRK_CANONICAL_CLOUD_BASE, RBTDRK_CANONICAL_RUNTIME_BASE);
37	    assert!(!RBTDRK_CANONICAL_CLOUD_BASE.ends_with('-'));
38	    assert!(!RBTDRK_CANONICAL_RUNTIME_BASE.ends_with('-'));
39	    assert!(RBTDRK_CANONICAL_CLOUD_BASE
40	        .chars()
41	        .all(|c| c.is_ascii_lowercase()));
42	    assert!(RBTDRK_CANONICAL_RUNTIME_BASE
43	        .chars()
44	        .all(|c| c.is_ascii_lowercase()));
45	}
46	
47	/// Composed canonical prefix shape: tinctured base ends with a hyphen and
48	/// stays disjoint between cloud and runtime.
49	#[test]
50	fn rbtdtk_canonical_prefix_compose() {
51	    let cloud = rbtdrk_canonical_cloud_prefix("xyz");
52	    let runtime = rbtdrk_canonical_runtime_prefix("xyz");
53	    assert!(cloud.ends_with('-'));
54	    assert!(runtime.ends_with('-'));
55	    assert_ne!(cloud, runtime);
56	    assert!(cloud.starts_with(RBTDRK_CANONICAL_CLOUD_BASE));
57	    assert!(runtime.starts_with(RBTDRK_CANONICAL_RUNTIME_BASE));
58	    assert!(cloud.contains("xyz"));
59	    assert!(runtime.contains("xyz"));
60	}
