62	/// Composed family stems are the base stem followed verbatim by the tincture.
63	/// Tied to RBTDRK_FAMILY_STEM_BASE rather than a literal so an era-bump of the
64	/// base (canest -> canest2 -> canest3 ...) can't silently desync this test.
65	#[test]
66	fn rbtdtk_family_stem_value() {
67	    assert_eq!(
68	        rbtdrk_family_stem("xyz"),
69	        format!("{}xyz", RBTDRK_FAMILY_STEM_BASE)
70	    );
71	}
