73	/// Distinct tinctures yield disjoint composed names (prefixes and family
74	/// stems) — the load-bearing disjointness property for parallel-station
75	/// runs on a shared payor manor.
76	#[test]
77	fn rbtdtk_canonical_disjoint_per_tincture() {
78	    assert_ne!(
79	        rbtdrk_canonical_cloud_prefix("aa"),
80	        rbtdrk_canonical_cloud_prefix("bb")
81	    );
82	    assert_ne!(
83	        rbtdrk_canonical_runtime_prefix("aa"),
84	        rbtdrk_canonical_runtime_prefix("bb")
85	    );
86	    assert_ne!(rbtdrk_family_stem("aa"), rbtdrk_family_stem("bb"));
87	}
