89	/// Dual-station dry-run for the canonical fixture: two distinct tinctures
90	/// produce disjoint depot project IDs, GAR repos, GCS buckets, and SA
91	/// emails — the wrap criterion for ₢BBABB. Mirrors RBDC composition rules
92	/// (rbdc_DerivedConstants.sh) without invoking GCP.
93	#[test]
94	fn rbtdtk_canonical_dual_station_disjoint() {
95	    let (a, b) = ("aaa", "bbb");
96	    let cloud_a = rbtdrk_canonical_cloud_prefix(a);
97	    let cloud_b = rbtdrk_canonical_cloud_prefix(b);
98	    let moniker_a = format!("{}100000", rbtdrk_family_stem(a));
99	    let moniker_b = format!("{}100000", rbtdrk_family_stem(b));
100	
101	    let project_a = format!("{}d-{}", cloud_a, moniker_a);
102	    let project_b = format!("{}d-{}", cloud_b, moniker_b);
103	    assert_ne!(project_a, project_b);
104	    assert!(project_a.len() <= 30, "project_a {} > 30", project_a);
105	    assert!(project_b.len() <= 30, "project_b {} > 30", project_b);
106	
107	    assert_ne!(
108	        format!("{}{}-gar", cloud_a, moniker_a),
109	        format!("{}{}-gar", cloud_b, moniker_b)
110	    );
111	
112	    assert_ne!(
113	        format!("{}b-{}", cloud_a, moniker_a),
114	        format!("{}b-{}", cloud_b, moniker_b)
115	    );
116	
117	    assert_ne!(
118	        format!("canest-ret@{}.iam.gserviceaccount.com", project_a),
119	        format!("canest-ret@{}.iam.gserviceaccount.com", project_b)
120	    );
121	}
