123	/// Canonical-establish is StateProgressing — the engine's keep-going
124	/// refusal applies to this fixture too, by design (per BBAAd policy gate).
125	#[test]
126	fn rbtdtk_disposition_is_state_progressing() {
127	    let fixture = rbtdrc_lookup_fixture(RBTDRM_FIXTURE_CANONICAL_ESTABLISH)
128	        .expect("canonical-establish is registered");
129	    assert_eq!(fixture.disposition, rbtdre_Disposition::StateProgressing);
130	}
