132	/// Case lookup binds the fixture name to the registry array and yields
133	/// exactly the four expected cases.
134	#[test]
135	fn rbtdtk_cases_registered() {
136	    let fixture = rbtdrc_lookup_fixture(RBTDRM_FIXTURE_CANONICAL_ESTABLISH)
137	        .expect("canonical-establish is registered");
138	    assert_eq!(fixture.cases.len(), 4, "expected four cases");
139	    let names: Vec<&str> = fixture.cases.iter().map(|c| c.name).collect();
140	    assert!(names.iter().any(|n| n.contains("rbtdrk_depot_levy")));
141	    assert!(names.iter().any(|n| n.contains("rbtdrk_governor_mantle")));
142	    assert!(names.iter().any(|n| n.contains("rbtdrk_retriever_invest")));
143	    assert!(names.iter().any(|n| n.contains("rbtdrk_director_invest")));
144	}
