146	/// install_canonical_prefixes refuses cleanly when rbrr.env is absent — the
147	/// helper does not silently succeed against a missing regime file.
148	#[test]
149	fn rbtdtk_install_canonical_prefixes_rejects_missing_rbrr() {
150	    let tmp: PathBuf = rbtdth_scratch_root().join("rbtdtk-nonexistent-root-xyz");
151	    let _ = std::fs::remove_dir_all(&tmp);
152	    std::fs::create_dir_all(&tmp).expect("create tempdir");
153	    let result = rbtdrk_install_canonical_prefixes(&tmp);
154	    let _ = std::fs::remove_dir_all(&tmp);
155	    assert!(result.is_err(), "expected Err when {}/rbrr.env is absent", crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR);
156	}
