886	        return v;
887	    }
888	
889	    let image_ref = format!("{}/{}/{}:{}", gar_root, ark_stem, RBTDRC_ARK_BASENAME_IMAGE, hallmark);
890	    let about_ref = format!("{}/{}/{}:{}", gar_root, ark_stem, RBTDRC_ARK_BASENAME_ABOUT, hallmark);
891	    let vouch_ref = format!("{}/{}/{}:{}", gar_root, ark_stem, RBTDRC_ARK_BASENAME_VOUCH, hallmark);
892	
893	    if let Err(v) = rbtdro_invoke_or_fail(
894	        ctx,
895	        "summon",
896	        &hallmark,
897	        RBTDGC_SUMMON_HALLMARK,
898	        &[&hallmark],
899	        &[],
900	        dir,
901	        "summon-conjure",
902	    ) {
903	        return v;
904	    }
905	    for ark_ref in [&image_ref, &about_ref, &vouch_ref] {
906	        if !rbtdrc_docker_inspect(ark_ref) {
907	            return rbtdre_Verdict::Fail(format!(
908	                "summon: ark not local after pull: {}",
909	                ark_ref
910	            ));
911	        }
912	    }
913	
914	    let plumb_full = match rbtdro_invoke_or_fail(
915	        ctx,
916	        "plumb_full",
917	        &hallmark,
918	        RBTDGC_PLUMB_FULL,
919	        &[&hallmark],
920	        &[],
921	        dir,
922	        "plumb-full-conjure",
923	    ) {
924	        Ok(r) => r,
925	        Err(v) => return v,
926	    };
927	    for marker in ["SLSA", "SBOM", "Dockerfile"] {
928	        if !plumb_full.stdout.contains(marker) {
929	            return rbtdre_Verdict::Fail(format!(
930	                "plumb_full: marker '{}' not in stdout",
931	                marker
932	            ));
933	        }
934	    }
935	
936	    let rekon = match rbtdro_invoke_or_fail(
937	        ctx,
938	        "rekon",
939	        &hallmark,
940	        RBTDGC_REKON_HALLMARK,
941	        &[&hallmark],
942	        &[],
943	        dir,
944	        "rekon-conjure",
945	    ) {
946	        Ok(r) => r,
947	        Err(v) => return v,
948	    };
949	    for basename in [
950	        RBTDRC_ARK_BASENAME_IMAGE,
951	        RBTDRC_ARK_BASENAME_ABOUT,
952	        RBTDRC_ARK_BASENAME_VOUCH,
953	        RBTDRC_ARK_BASENAME_ATTEST,
954	    ] {
955	        if !rbtdrc_rekon_basename_yes(&rekon.stdout, basename) {
956	            return rbtdre_Verdict::Fail(format!(
957	                "rekon: basename '{}' not marked yes\nstdout:\n{}",
958	                basename, rekon.stdout
959	            ));
960	        }
961	    }
962	
963	    for nameplate in RBTDRO_CONSUMERS_SENTRY_TETHER {
964	        if let Err(e) =
965	            rbtdro_drive_hallmark(&root, nameplate, RBTDRO_HALLMARK_VAR_SENTRY, &hallmark)
966	        {
967	            return rbtdre_Verdict::Fail(format!(
968	                "drive sentry hallmark into {}: {}",
969	                nameplate, e
970	            ));
971	        }
972	    }
973	
974	    let owned: Vec<String> = RBTDRO_CONSUMERS_SENTRY_TETHER
975	        .iter()
976	        .map(|n| rbtdro_nameplate_rbrn_path(n))
977	        .collect();
978	    if let Err(v) = rbtdro_git_commit(
979	        &owned,
980	        "ordain-conjure: sentry-tether hallmark + propagate to consumers",
981	    ) {
982	        return v;
983	    }
984	
985	    rbtdre_Verdict::Pass
986	}
